def gen(rng, size):
    n = max(1, min(size, 100))
    vals = rng.sample(range(1, 1001), n)
    # insert in this random order into a BST, then read preorder
    tree = {}
    root = None
    def insert(root, v):
        if root is None:
            return {'v': v, 'l': None, 'r': None}
        if v < root['v']:
            root['l'] = insert(root['l'], v)
        else:
            root['r'] = insert(root['r'], v)
        return root
    for v in vals:
        root = insert(root, v)
    out = []
    def pre(node):
        if node is None:
            return
        out.append(node['v'])
        pre(node['l'])
        pre(node['r'])
    pre(root)
    return [out]

