class Solution:
    def bstFromPreorder(self, preorder):
        root = None
        def insert(node, v):
            if node is None:
                return TreeNode(v)
            if v < node.val:
                node.left = insert(node.left, v)
            else:
                node.right = insert(node.right, v)
            return node
        for v in preorder:
            root = insert(root, v)
        return root

