class Solution:
    def bstFromPreorder(self, preorder):
        self.i = 0
        n = len(preorder)
        def build(bound):
            if self.i == n or preorder[self.i] > bound:
                return None
            val = preorder[self.i]
            self.i += 1
            node = TreeNode(val)
            node.left = build(val)
            node.right = build(bound)
            return node
        return build(float('inf'))

