var bstFromPreorder = function(preorder) {
    let i = 0;
    const n = preorder.length;
    const build = (bound) => {
        if (i === n || preorder[i] > bound) return null;
        const val = preorder[i];
        i += 1;
        const node = new TreeNode(val);
        node.left = build(val);
        node.right = build(bound);
        return node;
    };
    return build(Infinity);
};
